[{"fieldname": "print_heading_template", "fieldtype": "Custom HTML", "options": ""}, {"fieldtype": "Section Break", "label": ""}, {"fieldtype": "Column Break"}, {"fieldname": "_custom_html", "print_hide": 0, "label": "Custom HTML", "fieldtype": "HTML", "options": "{% set currency = frappe.db.get_value(
    "Company",
    doc.company,
    "default_currency"
) or "PKR" %}

{% set total_debit = frappe.utils.flt(doc.total_debit or 0) %}
{% set total_credit = frappe.utils.flt(doc.total_credit or 0) %}

<style>
.print-heading {
    border: 0 !important;
    display: none !important;
    height: 0 !important;
    margin: 0 !important;
    padding: 0 !important;
}

.print-format .letter-head {
    margin-bottom: 12px !important;
}

.br {
    color: #111;
    font-family: Arial, sans-serif;
    font-size: 11px;
    width: 100%;
}

.br * {
    box-sizing: border-box;
}

.br-meta,
.br-table,
.br-signatures{
    border-collapse: collapse;
    table-layout: fixed;
    width: 100%;
}

.br-meta {
    margin-bottom: 8px;
}

.br-meta td {
    border: 0 !important;
    height: 30px;
    line-height: 1.25;
    padding: 4px 6px !important;
    vertical-align: middle !important;
}

.br-label {
    font-weight: bold;
    white-space: nowrap;
    width: 12%;
}

.br-value {
    font-weight: bold;
    overflow-wrap: anywhere;
    width: 21.33%;
}

.br-table th,
.br-table td {
    border: 1px solid #555 !important;
    line-height: 1.3;
    padding: 6px !important;
    vertical-align: top !important;
}

.br-table th {
    background: #f3f3f3 !important;
    font-weight: bold;
    text-align: center;
}

.br-sr {
    text-align: center;
    width: 5%;
}

.br-account {
    overflow-wrap: anywhere;
    width: 30%;
}

.br-party {
    overflow-wrap: anywhere;
    width: 11%;
}

.br-cheque {
    overflow-wrap: anywhere;
    width: 10%;
}

.br-territory {
    overflow-wrap: anywhere;
    width: 21%;
}

.br-money {
    text-align: right;
    width: 11.5%;
}

.br-total-label,
.br-total-amount {
    font-weight: bold;
    text-align: right;
}

.br-notes {
    font-size: 11px;
    margin-top: 14px;
}

.br-notes p {
    margin: 0 0 6px;
}

.br-note-label {
    font-size: 12px;
    font-weight: bold;
}

.br-amount-words {
    font-weight: bold;
}

.br-signatures {
    margin-top: 70px;
}

.br-signatures td {
    border: 0 !important;
    padding: 0 15px !important;
    text-align: center;
    vertical-align: bottom !important;
    width: 25%;
}

.br-signature {
    border-top: 1px solid #111;
    display: block;
    padding-top: 6px;
}

@media print {
    .br-meta,
    .br-notes,
    .br-signatures {
        page-break-inside: avoid;
    }
    
    .br-table thead {
        display: table-header-group;
    }

    .br-table tr {
        page-break-inside: avoid;
    }
}
</style>

<div class="br">

    <table class="br-meta">
        <tbody>
            <tr>
                <td class="br-label">Voucher No:</td>
                <td class="br-value">
                    {{ doc.name or "-" }}
                </td>

                <td class="br-label">Date:</td>
                <td class="br-value">
                    {% if doc.posting_date %}
                        {{ frappe.utils.format_date(
                            doc.posting_date,
                            "dd-MM-yyyy"
                        ) }}
                    {% else %}
                        -
                    {% endif %}
                </td>

                <td class="br-label">Reference No:</td>
                <td class="br-value">
                    {{ doc.cheque_no or "-" }}
                </td>
            </tr>
        </tbody>
    </table>

    <table class="br-table">
        <thead>
            <tr>
                <th class="br-sr">SR.</th>
                <th class="br-account">Account</th>
                <th class="br-party">Party</th>
                <th class="br-cheque">Cheque No</th>
                <th class="br-territory">Territory</th>
                <th class="br-money">DR</th>
                <th class="br-money">CR</th>
            </tr>
        </thead>

        <tbody>
            {% for row in doc.accounts %}

                {% set territory =
                    row.get("territory")
                    or row.get("custom_territory")
                %}

                {% if not territory
                    and row.party
                    and row.party_type == "Customer" %}

                    {% set territory = frappe.db.get_value(
                        "Customer",
                        row.party,
                        "territory"
                    ) %}

                {% elif not territory
                    and row.party
                    and row.party_type == "Donor" %}

                    {% set territory = frappe.db.get_value(
                        "Donor",
                        row.party,
                        "territory"
                    ) %}

                {% endif %}

                <tr>
                    <td class="br-sr">
                        {{ loop.index }}
                    </td>

                    <td class="br-account">
                        {{ row.account or "-" }}
                    </td>

                    <td class="br-party">
                        {{ row.party or "-" }}
                    </td>

                    <td class="br-cheque">
                        {{ doc.cheque_no or "-" }}
                    </td>

                    <td class="br-territory">
                        {{ territory or "-" }}
                    </td>

                    <td class="br-money">
                        {% if frappe.utils.flt(row.debit) %}
                            {{ frappe.utils.fmt_money(
                                row.debit,
                                currency=currency
                            ) }}
                        {% else %}
                            -
                        {% endif %}
                    </td>

                    <td class="br-money">
                        {% if frappe.utils.flt(row.credit) %}
                            {{ frappe.utils.fmt_money(
                                row.credit,
                                currency=currency
                            ) }}
                        {% else %}
                            -
                        {% endif %}
                    </td>
                </tr>

            {% endfor %}

            <tr>
                <td class="br-total-label" colspan="5">
                    Total:
                </td>

                <td class="br-total-amount">
                    {{ frappe.utils.fmt_money(
                        total_debit,
                        currency=currency
                    ) }}
                </td>

                <td class="br-total-amount">
                    {{ frappe.utils.fmt_money(
                        total_credit,
                        currency=currency
                    ) }}
                </td>
            </tr>
        </tbody>
    </table>

    <div class="br-notes">
        <p>
            <span class="br-note-label">Remark:</span>
            {{ doc.user_remark or "-" }}
        </p>

        <p>Amount in Words</p>

        <p class="br-amount-words">
            {{ frappe.utils.money_in_words(
                total_debit,
                currency
            ) }}
        </p>
    </div>
        <table class="br-signatures">
        <tbody>
            <tr>
                <td>
                    <span class="br-signature">Prepared By</span>
                </td>

                <td>
                    <span class="br-signature">Checked By</span>
                </td>

                <td>
                    <span class="br-signature">
                        Manager Finance
                    </span>
                </td>

                <td>
                    <span class="br-signature">
                        Approved By / CEO
                    </span>
                </td>
            </tr>
        </tbody>
    </table>

</div>"}]
